const express = require('express');

const app = express();
const PORT = process.env.PORT || 3000;

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Remove the X-Powered-By header to avoid leaking framework info
app.disable('x-powered-by');

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters (e.g., pagination)
  const limit = parseInt(req.query.limit, 10);
  const offset = parseInt(req.query.offset, 10);

  if (req.query.limit !== undefined && (isNaN(limit) || limit < 1 || limit > 100)) {
    return res.status(400).json({ error: 'limit must be an integer between 1 and 100' });
  }
  if (req.query.offset !== undefined && (isNaN(offset) || offset < 0)) {
    return res.status(400).json({ error: 'offset must be a non-negative integer' });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  const start = offset || 0;
  const end = limit ? start + limit : users.length;

  res.json(users.slice(start, end));
});

// ---------------------------------------------------------------------------
// 404 handler — catch unmatched routes
// ---------------------------------------------------------------------------

app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ---------------------------------------------------------------------------
// Global error handler — prevent leaking stack traces
// ---------------------------------------------------------------------------

app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error'
        : err.message,
  });
});

// ---------------------------------------------------------------------------
// Start server with graceful shutdown
// ---------------------------------------------------------------------------

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

function shutdown(signal) {
  console.log(`${signal} received — shutting down gracefully`);
  server.close(() => {
    console.log('HTTP server closed');
    process.exit(0);
  });
  // Force exit if graceful shutdown takes too long
  setTimeout(() => process.exit(1), 10_000);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

module.exports = app;

